local LxNodeBase = require("LApp.component.LxNodeBase")
---@class UIIconEasyList
local UIIconEasyList = LxClass("UIIconEasyList", LxNodeBase)
-----------------------------------------------------------------
function UIIconEasyList:UIIconEasyList(wndClass)
	self._uiList = nil
	self._wndClass = wndClass
	---@type LWnd
	self._parentWnd = nil

	self._bInit = false
	self._isDestroy = false

	---@type table<number, CommonIcon>
	self._iconList = {}

	self._iconParentPath = "CommonUI/Icon"
	self._iconClickPath = ""

	self._iconExtraNumPath = ""
	self._bShowExtraNum = false
	self._iconMaskPath = ""
	self._bShowMask = false
	self._bShowMaskIndex = nil
	self._iconTabPath = ""
	self._iconTabImg = ""
	self._bShowTab = false

	self._bEnableIconAni = false
	self._iconAniPath = "CommonUI"
	self._iconAniTime = 0.2

	self._bShowNum = true
	self._bEnableTouch = true

    self._isDetail = false

	self._seqList = {}
end

function UIIconEasyList:Create(parentWnd, scrollTrans, anchorType,isDetail, itemDrawCall)
	if self._isDestroy then return end
	if self._bInit then return end
	self._bInit = true

	local onDrawIconFunc
	isDetail = isDetail and true or false
    self._isDetail = isDetail
	if isDetail then
		onDrawIconFunc = function(...)
			self:OnDrawDetailIcon(...)
		end
	else
		onDrawIconFunc = function(...)
			self:OnDrawIcon(...)
		end
	end

	self._parentWnd = parentWnd
	local uiList = UIListEasy:New()
	uiList:Create(parentWnd, scrollTrans,anchorType)
	uiList:SetFuncOnItemDraw(function(...)
		onDrawIconFunc(...)
		if itemDrawCall then
			itemDrawCall(...)
		end
	end)
	self._uiList = uiList
end

