---配置表的不需要转换，协议中的RewardItem结构需要转换
function UIIconEasyList:RefreshList(dataList, isTranslate)
	if self._isDestroy then return end
	if not self._bInit then return end
	local uiList = self._uiList
	uiList:RemoveAll()

	dataList = dataList or {}
	if isTranslate and not self._isDetail then
        local tempList = {}
        for k,v in ipairs(dataList) do
            table.insert(tempList,{
                itemId = v.itemId or v.refId,
                itemNum = tonumber(v.count) or tonumber(v.itemNum),
                itemType = v.type or v.itemType,
                index = k,
				constData = v,
            })
        end
        dataList = tempList
	end

	self._isIconAni = {}

	for k,v in ipairs(dataList) do
		uiList:AddData(k, v)
	end

	uiList:RefreshList()
end

function UIIconEasyList:GetCommonIconTrans(item)
	local iconParentPath = self._iconParentPath or "CommonUI/Icon"
	local iconTrans = CS.FindTrans(item, iconParentPath)
	return iconTrans
end

function UIIconEasyList:GetCommonIcon(item)
	local iconList = self._iconList
	if not iconList then
		iconList = {}
		self._iconList = iconList
	end
	local instanceId = item:GetInstanceID()
	local baseClass = iconList[instanceId]

	if not baseClass then
		baseClass = CommonIcon:New()
		iconList[instanceId] = baseClass
	end
	return baseClass
end

function UIIconEasyList:ShowNeedNumStatus(baseClass)
	if not baseClass then return end
	if self._bNeedNumStatus then
		baseClass:ShowNeedNumStatus(self._bNeedNumStatus, self._bShowNumType)
	end
end

function UIIconEasyList:SetEffRoot(item,itemdata,itempos)
	local instanceId = item:GetInstanceID()
	local effRoot = CS.FindTrans(item,"Eff")
	if effRoot then
		if self._wndClass and (itemdata.isShowEff or self._effName) and not self._isOnEff then
			local itemId = itemdata.itemId
			CS.ShowObject(effRoot,true)
			local ref = gModelItem:GetRefByRefId(itemId)
			local bgEff = self._effName or (ref and ref.bgEff)
			local _effSize = self._effSize or 114
			local instanceID = self._instanceID or instanceId
			if not string.isempty(bgEff) then
				local effKey = bgEff .. itemId..instanceID..itempos
				self._wndClass:DestroyWndEffectByKey(effKey)
				self._wndClass:CreateWndEffect(effRoot,bgEff,effKey,_effSize,false,false)
			end
		else
			LxResUtil.DestroyChildImmediate(effRoot)
			CS.ShowObject(effRoot,false)
		end
	end
end

function UIIconEasyList:SetIconClickFunc(iconTrans,item,clickFunc)
	if not self._bEnableTouch then return end
	local iconClickPath = self. _iconClickPath
	local clickTrans = iconTrans
	if not string.isempty(iconClickPath) then
		clickTrans = self:GetCommonIconTrans(item)
	end
	if clickTrans then
		self._parentWnd:SetIconClickScale(clickTrans, true)
		self._parentWnd:SetWndClick(clickTrans,function()
			if not clickFunc then return end
			clickFunc()
		end)
	end
end

function UIIconEasyList:SetExtraNumTrans(item,itemdata)
	if not self._parentWnd then return end
	if not self._bShowExtraNum then return end
	if string.isempty(self._iconExtraNumPath) then return end
	local extraNumTrans = CS.FindTrans(item, self._iconExtraNumPath)
	local itemNumStr = ""
	local itemNum = itemdata.itemNum
	if itemNum and itemNum > 0 then
		itemNumStr = LUtil.NumberCoversion(itemNum)
	end
	self._parentWnd:SetWndText(extraNumTrans, itemNumStr)
end

function UIIconEasyList:SetMaskTrans(item,itempos)
	if string.isempty(self._iconMaskPath) then return end
	local maskPath = self._iconMaskPath
	local isMask = self._bShowMask
	local index = self._bShowMaskIndex
	local mask = CS.FindTrans(item, maskPath)
	CS.ShowObject(mask,isMask or index == itempos)
end

function UIIconEasyList:SetTabTrans(item)
	if string.isempty(self._iconTabPath) then return end
	if string.isempty(self._iconTabImg) then return end

	local isTab = self._bShowTab
	local tabPath = self._iconTabPath
	local tabImg = self._iconTabImg
	local tab = CS.FindTrans(item, tabPath)
	local rootTrans = nil
	if self._wndClass then
		rootTrans = self._wndClass:GetWndTrans()
	end
	self:SetImage(tab, tabImg)
	CS.ShowObject(tab,isTab)
end

function UIIconEasyList:RunAni(item,itemdata,itempos)
	if not self._bEnableIconAni then return end
	local instanceId = item:GetInstanceID()
	self:DoPlayAni(instanceId, item, itemdata, itempos)
end

function UIIconEasyList:OnDrawIcon(list,item,itemData,itemPos)
	local itemId = itemData.itemId
	local itemNum = itemData.itemNum
	local itemType = itemData.itemType

	local iconTrans = self:GetCommonIconTrans(item)
	local baseClass = self:GetCommonIcon(item)
	baseClass:Create(iconTrans)
	baseClass:SetCommonReward(itemType, itemId, itemNum)
	baseClass:EnableShowNum(self._bShowNum)
	self:ShowNeedNumStatus(baseClass)
	baseClass:DoApply()

	self:SetEffRoot(item,itemData,itemPos)

	self:SetIconClickFunc(iconTrans,item,function()
		local data = {
			itemId = itemId,
			itemType = itemType,
			itemNum = itemNum,
		}
		if self._extraClickFunc then
			self._extraClickFunc(data)
		else
			gModelGeneral:ShowCommonItemTipWnd(data,{showSkinCode=true})
		end
	end)

	self:SetExtraNumTrans(item,itemData)

	self:SetMaskTrans(item,itemPos)

	self:SetTabTrans(item)

	self:RunAni(item, itemData, itemPos)
end

function UIIconEasyList:OnDrawDetailIcon(list,item,itemdata,itempos)
	local serverData = itemdata.serverData or itemdata


	local iconTrans = self:GetCommonIconTrans(item)
	local baseClass = self:GetCommonIcon(item)
	baseClass:Create(iconTrans)
	baseClass:SetRewardDetailItem(serverData)
	baseClass:EnableShowNum(self._bShowNum)
	self:ShowNeedNumStatus(baseClass)
	baseClass:DoApply()

	self:SetEffRoot(item,serverData,itempos)

	self:SetIconClickFunc(iconTrans,item,function()
		gModelGeneral:ShowRewardDetailTip(serverData)
	end)

	self:SetExtraNumTrans(item,serverData)

	self:SetMaskTrans(item,itempos)

	self:SetTabTrans(item)

	self:RunAni(item, serverData, itempos)
end
-----------------------------------------------------------------
function UIIconEasyList:DoPlayAni(instanceId, item, itemData, itemPos)
	local seq = self._seqList[instanceId]
	if seq then
		seq:Kill(false)
		self._seqList[instanceId] = nil
	end

	local aniTrans = CS.FindTrans(item, self._iconAniPath or "CommonUI")

	if self._isIconAni[itemPos] then
		aniTrans.localScale = Vector3.one
		return
	end

	self._isIconAni[itemPos] = true

	aniTrans.localScale = Vector3.zero
	local dtSequence = YXTween.TweenSequenceIns()
	self._seqList[instanceId] = dtSequence

	local playTime = self._iconAniTime
	local startT = itemPos * playTime
	local ani1 = aniTrans:DOScale(1, playTime)

	dtSequence:AppendInterval(startT)
	dtSequence:Append(ani1)
	dtSequence:OnComplete(function()
		self._seqList[instanceId] = nil
	end)
	dtSequence:PlayForward()
end

-----------------------------------------------------------------
function UIIconEasyList:EnableScroll(enabled,isHorizontal)
	if self._uiList then
		self._uiList:EnableScroll(enabled,isHorizontal)
	end
end

function UIIconEasyList:EnableLoadAnimation(bEnable, aniTime, onceCount, aniType)
	if self._uiList then
		self._uiList:EnableLoadAnimation(bEnable, aniTime, onceCount, aniType)
	end
end
---@return UIListEasy
function UIIconEasyList:GetUIList()
	return self._uiList
end

------------------------------------------------------------------
function UIIconEasyList:Destroy()
	if self._isDestroy then return end

	if self._seqList then
		local seqList = self._seqList
		for k, v in pairs(seqList) do
			v:Kill(false)
			seqList[k] = nil
		end
		self._seqList = nil
	end

	if self._iconList then
		local iconList = self._iconList
		for k,v in pairs(iconList) do
			v:Destroy()
			iconList[k] = nil
		end
		self._iconList = nil
	end

	if self._uiList then
		self._uiList:Destroy()
	end

	LxNodeBase.Dispose(self)

	self._isDestroy = true
end
------------------------------------------------------------------

return UIIconEasyList